validation.test_code:
void test_crc8_bitwise_single_byte(void) {
    unsigned char poly = 0x07;
    unsigned char msg[] = {0x00};
    TEST_ASSERT_EQUAL_INT(0x00, crc8_bitwise(msg, 1, poly));
}

void test_crc8_bitwise_messages(void) {
    unsigned char poly = 0x07;
    unsigned char msg2[] = {0x01, 0x02, 0x03};
    unsigned char msg3[] = {'H', 'e', 'l', 'l', 'o'};
    unsigned char msg4[] = {0xFF, 0xFF, 0xFF, 0xFF};
    TEST_ASSERT_EQUAL_INT(0x48, crc8_bitwise(msg2, 3, poly));
    TEST_ASSERT_EQUAL_INT(0xF6, crc8_bitwise(msg3, 5, poly));
    TEST_ASSERT_EQUAL_INT(0xDE, crc8_bitwise(msg4, 4, poly));
}

void test_crc8_table_consistency(void) {
    unsigned char poly = 0x07;
    unsigned char table[256];
    build_crc8_table(table, poly);
    unsigned char msg[] = {0x01, 0x02, 0x03};
    TEST_ASSERT_EQUAL_INT(crc8_bitwise(msg, 3, poly), crc8_table(msg, 3, table));
}

void test_crc8_table_all_messages(void) {
    unsigned char poly = 0x07;
    unsigned char table[256];
    build_crc8_table(table, poly);
    unsigned char msg1[] = {0x00};
    unsigned char msg2[] = {'H', 'e', 'l', 'l', 'o'};
    unsigned char msg3[] = {0xFF, 0xFF, 0xFF, 0xFF};
    TEST_ASSERT_EQUAL_INT(0x00, crc8_table(msg1, 1, table));
    TEST_ASSERT_EQUAL_INT(0xF6, crc8_table(msg2, 5, table));
    TEST_ASSERT_EQUAL_INT(0xDE, crc8_table(msg3, 4, table));
}

int main(void) {
    RUN_TEST(test_crc8_bitwise_single_byte);
    RUN_TEST(test_crc8_bitwise_messages);
    RUN_TEST(test_crc8_table_consistency);
    RUN_TEST(test_crc8_table_all_messages);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

