/* == EXEMPLE ================================================
 * CRC = division polynomiale binaire via XOR
 * Si MSB=1: shift gauche + XOR avec polynôme
 * Si MSB=0: shift gauche seulement
 * =========================================================== */
void example_crc(void) {
    unsigned char crc = 0x01;
    unsigned char poly = 0x07;
    for (int bit = 0; bit < 8; bit++) {
        if (crc & 0x80)
            crc = (crc << 1) ^ poly;
        else
            crc <<= 1;
    }
    printf("CRC of 0x01 = 0x%02X\n", crc);
}

